public:
    // Assuming Window stores a pointer/reference to the underlying SDL_Window
    Renderer(const Window& window, bool vsync) : windowRef(window) {
        CreateRenderer(vsync);
    }

    ~Renderer() {
        if (renderer) {
            SDL_DestroyRenderer(renderer);
        }
    }

    void CheckHealthAndRecreateIfNeeded(bool vsync) {
        if (!IsRendererHealthy()) { // Implement this to determine health
            Recreate(vsync);
        }
