    void Recreate(bool vsync) {
        if (renderer) {
            SDL_DestroyRenderer(renderer);
            renderer = nullptr;
        }
        CreateRenderer(vsync);
        // May need additional logic to reinitialize any resources tied to the old renderer
    }

    // Dummy placeholder for health check method -- you'll need to implement this
    bool IsRendererHealthy() const {
        return true; // Placeholder implementation
    }
};

// Note: Ensure the Window class provides access to its SDL_Window instance,
// for example through a GetWindow() method as hinted at above.
```

